const items = $input.all();
if (items.length === 0) return [];

// 1. Extrair e ordenar os valores de consumo do menor para o maior
const values = items
    .map(item => parseFloat(item.json.media_consumo))
    .sort((a, b) => a - b);

// 2. Função auxiliar para calcular os percentis (interpolação linear)
function getPercentile(data, percentile) {
    const index = (percentile / 100) * (data.length - 1);
    const lower = Math.floor(index);
    const upper = Math.ceil(index);
    const weight = index - lower;

    if (upper === lower) return data[lower];
    return data[lower] * (1 - weight) + data[upper] * weight;
}

// 3. Calcular Q1 (25%), Q3 (75%) e o IQR
const q1 = getPercentile(values, 25);
const q3 = getPercentile(values, 75);
const iqr = q3 - q1;

// 4. Definir os limites (Multiplier padrão estatístico é 1.5)
const lowerThreshold = q1 - (1.5 * iqr);
const upperThreshold = q3 + (1.5 * iqr);

// 5. Classificar os dados originais com base nos novos limites
const processedData = items.map(item => {
    const media = parseFloat(item.json.media_consumo);
    let status = 'normal';

    if (media > upperThreshold || media < lowerThreshold) {
        status = 'outlier';
    }

    return {
        "Nome do cliente": item.json['Nome do cliente'],
        "Média de consumo": Number(media.toFixed(4)),
        "Status": status
    };
});

// Opcional: Adicionando dados de debug no output para você conferir os cálculos
return [{ 
    json: { 
        relatorio_dados: processedData,
        debug_estatistico: {
            q1: Number(q1.toFixed(4)),
            q3: Number(q3.toFixed(4)),
            iqr: Number(iqr.toFixed(4)),
            limite_inferior: Number(lowerThreshold.toFixed(4)),
            limite_superior: Number(upperThreshold.toFixed(4))
        }
    } 
}];
